import React, { useState, useEffect } from 'react';
import { resolveUrl } from '../utils';
import { Dialog } from 'primereact/dialog';
import { Rating } from 'primereact/rating';
import { Button } from 'primereact/button';

function ItemDetailDialog({ item, visible, onHide, onDelete, isOwner, onReserve, onUnreserve, autoOpenPrivacy = false }) {
  const [privacyOpen, setPrivacyOpen] = useState(false);
  const [privacyOption, setPrivacyOption] = useState('not_selected');
  
  // Автоматически открываем выпадающий список если autoOpenPrivacy = true
  useEffect(() => {
    if (visible && autoOpenPrivacy && !isOwner && !item?.reservedByMe && !item?.isReserved) {
      setPrivacyOpen(true);
    }
  }, [visible, autoOpenPrivacy, isOwner, item]);
  
  // Сбрасываем состояние при закрытии диалога
  useEffect(() => {
    if (!visible) {
      setPrivacyOpen(false);
      setPrivacyOption('not_selected');
    }
  }, [visible]);
  
  if (!item) return null;

  const headerTemplate = () => {
    return (
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', width: '100%' }}>
        <span style={{ fontSize: '20px', fontWeight: 600 }}>Детали подарка</span>
        {isOwner && onDelete && (
          <Button
            icon="pi pi-trash"
            className="p-button-rounded p-button-text p-button-danger"
            onClick={() => { onDelete(item.id); onHide(); }}
            tooltip="Удалить подарок"
            tooltipOptions={{ position: 'bottom' }}
            style={{ marginRight: '8px' }}
          />
        )}
      </div>
    );
  };

  return (
    <Dialog
      visible={visible}
      onHide={onHide}
      className="item-detail-dialog"
      header={headerTemplate()}
      closable
      headerStyle={{ padding: '1.5rem', borderBottom: '1px solid #e0e0e0' }}
      contentStyle={{ padding: '1.5rem' }}
    >
      <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
        {/* Изображение */}
        <div style={{ 
          width: '100%', 
          height: '300px', 
          background: '#f5f5f5',
          borderRadius: '12px',
          overflow: 'hidden',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center'
        }}>
          {item.imageUrl ? (
            <img
              src={resolveUrl(item.imageUrl)}
              alt={item.title}
              style={{
                width: '100%',
                height: '100%',
                objectFit: 'contain'
              }}
            />
          ) : (
            <i className="pi pi-image" style={{ fontSize: '4rem', color: '#ccc' }}></i>
          )}
        </div>

        {/* Название и рейтинг */}
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
          <h2 style={{ margin: 0, fontSize: '24px', fontWeight: 600, color: '#000' }}>
            {item.title}
          </h2>
          {item.reservedByMe && (
            <div style={{
              width: '40px',
              height: '40px',
              borderRadius: '50%',
              background: '#e91e63',
              color: 'white',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              fontSize: '18px',
              fontWeight: 600
            }}>
              B
            </div>
          )}
        </div>

        {/* Рейтинг */}
        {item.priority && (
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
            <Rating value={item.priority} readOnly cancel={false} onIcon={<img src="/images/path-2.svg" alt="heart" width="20px" height="20px" />} offIcon={<img src="/images/ti-heart.svg" alt="heart" width="20px" height="20px" />} />
          </div>
        )}

        {/* Цена и ссылка */}
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
          {item.price && (
            <div style={{ fontSize: '24px', fontWeight: 600, color: '#000' }}>
              {item.price} ₽
            </div>
          )}
          {item.url && (
            <a
              href={item.url}
              target="_blank"
              rel="noopener noreferrer"
              style={{ 
                color: '#188700', 
                textDecoration: 'none',
                display: 'flex',
                alignItems: 'center',
                gap: '6px',
                fontSize: '16px',
                fontWeight: 500
              }}
            >
              Ссылка <i className="pi pi-external-link"></i>
            </a>
          )}
        </div>

        {/* Комментарий */}
        {item.description && (
          <div>
            <div style={{ 
              fontSize: '14px', 
              color: '#999', 
              marginBottom: '8px',
              fontWeight: 500
            }}>
              Комментарий
            </div>
            <div style={{ 
              fontSize: '14px', 
              color: '#666',
              lineHeight: '1.6'
            }}>
              {item.description}
            </div>
          </div>
        )}

        {/* Кнопка бронирования для не-владельца */}
        {!isOwner && (
          <div style={{ marginTop: '1rem' }}>
            {/* Приватность бронирования */}
            <div style={{ marginBottom: '1rem', position: 'relative' }}>
              <div style={{ 
                display: 'flex', 
                alignItems: 'center', 
                gap: '8px',
                marginBottom: '12px',
                fontSize: '16px',
                fontWeight: '500',
                color: '#1e293b'
              }}>
                <span>Приватность бронирования подарка</span>
                <i className="pi pi-gift" style={{ fontSize: '18px', color: '#188700' }}></i>
              </div>
              
              <div 
                onClick={() => setPrivacyOpen(!privacyOpen)}
                style={{
                  width: '100%',
                  padding: '14px 16px',
                  borderRadius: '12px',
                  border: '2px solid #188700',
                  fontSize: '16px',
                  color: '#94a3b8',
                  backgroundColor: 'white',
                  cursor: 'pointer',
                  display: 'flex',
                  justifyContent: 'space-between',
                  alignItems: 'center',
                  marginBottom: privacyOpen ? '0' : '12px'
                }}
              >
                <span>
                  {privacyOption === 'not_selected' && 'Не выбрана'}
                  {privacyOption === 'show_name' && 'Показывать имя при бронировании'}
                  {privacyOption === 'hide_name' && 'Скрыть имя при бронировании'}
                  {privacyOption === 'incognito' && 'Скрыть факт бронирования "Инкогнито"'}
                </span>
                <i className={`pi ${privacyOpen ? 'pi-chevron-up' : 'pi-chevron-down'}`} style={{ fontSize: '14px', color: '#1e293b' }}></i>
              </div>
              
              {/* Выпадающий список */}
              {privacyOpen && (
                <div style={{
                  position: 'absolute',
                  top: '56px',
                  left: 0,
                  width: '100%',
                  backgroundColor: 'white',
                  border: '1px solid #e5e7eb',
                  borderRadius: '12px',
                  boxShadow: '0 4px 12px rgba(0,0,0,0.15)',
                  zIndex: 1000,
                  padding: '8px'
                }}>
                  <div 
                    onClick={() => { setPrivacyOption('show_name'); setPrivacyOpen(false); }}
                    style={{
                      padding: '10px 12px',
                      cursor: 'pointer',
                      display: 'flex',
                      alignItems: 'center',
                      gap: '12px',
                      borderRadius: '6px',
                      transition: 'background 0.2s'
                    }}
                    onMouseEnter={(e) => e.currentTarget.style.background = '#f9fafb'}
                    onMouseLeave={(e) => e.currentTarget.style.background = 'transparent'}
                  >
                    <div style={{
                      width: '22px',
                      height: '22px',
                      minWidth: '22px',
                      borderRadius: '50%',
                      border: `3px solid ${privacyOption === 'show_name' ? '#188700' : '#d1d5db'}`,
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      backgroundColor: 'white'
                    }}>
                      {privacyOption === 'show_name' && (
                        <div style={{
                          width: '10px',
                          height: '10px',
                          borderRadius: '50%',
                          background: '#188700'
                        }}></div>
                      )}
                    </div>
                    <span style={{ fontSize: '15px', color: '#188700', fontWeight: '400' }}>Показывать имя при бронировании</span>
                  </div>
                  
                  <div 
                    onClick={() => { setPrivacyOption('hide_name'); setPrivacyOpen(false); }}
                    style={{
                      padding: '10px 12px',
                      cursor: 'pointer',
                      display: 'flex',
                      alignItems: 'center',
                      gap: '12px',
                      borderRadius: '6px',
                      transition: 'background 0.2s'
                    }}
                    onMouseEnter={(e) => e.currentTarget.style.background = '#f9fafb'}
                    onMouseLeave={(e) => e.currentTarget.style.background = 'transparent'}
                  >
                    <div style={{
                      width: '22px',
                      height: '22px',
                      minWidth: '22px',
                      borderRadius: '50%',
                      border: `3px solid ${privacyOption === 'hide_name' ? '#188700' : '#d1d5db'}`,
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      backgroundColor: 'white'
                    }}>
                      {privacyOption === 'hide_name' && (
                        <div style={{
                          width: '10px',
                          height: '10px',
                          borderRadius: '50%',
                          background: '#188700'
                        }}></div>
                      )}
                    </div>
                    <span style={{ fontSize: '15px', color: '#475569', fontWeight: '400' }}>Скрыть имя при бронировании</span>
                  </div>
                  
                  <div 
                    onClick={() => { setPrivacyOption('incognito'); setPrivacyOpen(false); }}
                    style={{
                      padding: '10px 12px',
                      cursor: 'pointer',
                      display: 'flex',
                      alignItems: 'center',
                      gap: '12px',
                      borderRadius: '6px',
                      transition: 'background 0.2s'
                    }}
                    onMouseEnter={(e) => e.currentTarget.style.background = '#f9fafb'}
                    onMouseLeave={(e) => e.currentTarget.style.background = 'transparent'}
                  >
                    <div style={{
                      width: '22px',
                      height: '22px',
                      minWidth: '22px',
                      borderRadius: '50%',
                      border: `3px solid ${privacyOption === 'incognito' ? '#188700' : '#d1d5db'}`,
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      backgroundColor: 'white'
                    }}>
                      {privacyOption === 'incognito' && (
                        <div style={{
                          width: '10px',
                          height: '10px',
                          borderRadius: '50%',
                          background: '#188700'
                        }}></div>
                      )}
                    </div>
                    <span style={{ fontSize: '15px', color: '#475569', fontWeight: '400' }}>Скрыть факт бронирования "Инкогнито"</span>
                  </div>
                </div>
              )}
              
              {!privacyOpen && (
                <p style={{ 
                  fontSize: '14px', 
                  color: '#94a3b8', 
                  margin: 0,
                  lineHeight: '1.5'
                }}>
                  Хотите подписаться своим именем или остаться анонимным?
                </p>
              )}
            </div>

            {item.reservedByMe ? (
              <button
                onClick={() => { onUnreserve(item); onHide(); }}
                style={{
                  width: '100%',
                  height: '45px',
                  borderRadius: '8px',
                  background: 'white',
                  color: '#188700',
                  border: '2px solid #188700',
                  fontSize: '16px',
                  fontWeight: '600',
                  cursor: 'pointer',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  gap: '8px',
                  transition: 'all 0.2s'
                }}
                onMouseEnter={(e) => {
                  e.currentTarget.style.background = '#F0FDF4';
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.background = 'white';
                }}
              >
                <i className="pi pi-times" style={{ fontSize: '18px' }}></i>
                Отменить бронь
              </button>
            ) : !item.isReserved ? (
              <button
                onClick={() => { 
                  // Определяем режим приватности
                  const isIncognito = privacyOption === 'incognito';
                  onReserve(item, privacyOption); 
                  onHide(); 
                }}
                disabled={privacyOption === 'not_selected'}
                style={{
                  width: '100%',
                  height: '45px',
                  borderRadius: '8px',
                  background: privacyOption === 'not_selected' ? '#cccccc' : '#188700',
                  color: 'white',
                  border: 'none',
                  fontSize: '16px',
                  fontWeight: '600',
                  cursor: privacyOption === 'not_selected' ? 'not-allowed' : 'pointer',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  gap: '8px',
                  transition: 'background 0.2s'
                }}
                onMouseEnter={(e) => {
                  if (privacyOption !== 'not_selected') {
                    e.currentTarget.style.background = '#146600';
                  }
                }}
                onMouseLeave={(e) => {
                  if (privacyOption !== 'not_selected') {
                    e.currentTarget.style.background = '#188700';
                  }
                }}
              >
                <i className="pi pi-gift" style={{ fontSize: '18px' }}></i>
                Забронировать
              </button>
            ) : (
              <button
                disabled
                style={{
                  width: '100%',
                  height: '45px',
                  borderRadius: '8px',
                  background: '#cccccc',
                  color: '#666666',
                  border: 'none',
                  fontSize: '16px',
                  fontWeight: '600',
                  cursor: 'not-allowed',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  gap: '8px'
                }}
              >
                <i className="pi pi-lock" style={{ fontSize: '18px' }}></i>
                Забронировано
              </button>
            )}
          </div>
        )}
      </div>
    </Dialog>
  );
}

export default ItemDetailDialog;
